export function normalizeSurahLookupKey(raw) {
    return raw
        .toLowerCase()
        .trim()
        .replace(/[`'’´]+/g, "")
        .replace(/[\u00ad\u2010\u2011\u2012\u2013\u2014\u2212\s\-_.]+/g, "");
}
let _map = null;
/** Normalisierter englischer Sure-Name → Sure-ID (1–114). */
export function surahNameToId() {
    if (_map)
        return _map;
    const m = new Map();
    for (let i = 0; i < RAW_EN.length; i++) {
        const id = i + 1;
        m.set(normalizeSurahLookupKey(RAW_EN[i]), id);
    }
    // Häufige Varianten
    m.set(normalizeSurahLookupKey("At-Taubah"), 9);
    m.set(normalizeSurahLookupKey("Al-Tawbah"), 9);
    m.set(normalizeSurahLookupKey("Baqarah"), 2);
    m.set(normalizeSurahLookupKey("Al Imran"), 3);
    _map = m;
    return _map;
}
